-- Add 12 Content team members (name, EMP ID, company email). Roster gate for SSO
-- + task assignment. dept/sub/manager left null — set them via Admin > Employees
-- (email is editable there). Re-runnable (upsert by id).
on conflict (id) do update set
  email = excluded.email, name = excluded.name, initials = excluded.initials,
  role_level = excluded.role_level, title = excluded.title, data = excluded.data;
